#include <stdio.h>
#include <math.h>

int main(void) {
    double x[4], y[4];
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Function to calculate the area of a triangle using Heron's formula
    double calculateArea(double a, double b, double c) {
        double s = (a + b + c) / 2.0;
        return sqrt(s * (s - a) * (s - b) * (s - c));
    }

    // Function to check if three points are collinear
    int areCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
        return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
    }

    // Generate all combinations of 3 points
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                double a = sqrt((x[i] - x[j]) * (x[i] - x[j]) + (y[i] - y[j]) * (y[i] - y[j]));
                double b = sqrt((x[j] - x[k]) * (x[j] - x[k]) + (y[j] - y[k]) * (y[j] - y[k]));
                double c = sqrt((x[k] - x[i]) * (x[k] - x[i]) + (y[k] - y[i]) * (y[k] - y[i]));

                if (!areCollinear(x[i], y[i], x[j], y[j], x[k], y[k])) {
                    double area = calculateArea(a, b, c);
                    printf("area, %.3f\n", area);
                } else {
                    printf("collinear\n");
                }
            }
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

void generateRandomNumbers(int numbers[]) {
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }
}

void displayNumbers(int numbers[]) {
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("* ");
    }
    printf("\n");
}

void playGame() {
    int numbers[NUM_NUMBERS];
    generateRandomNumbers(numbers);

    int guessedPositions[NUM_NUMBERS] = {0};
    int score = 0;

    while (1) {
        displayNumbers(numbers);
        printf("Pick a position (1-%d): ", NUM_NUMBERS);
        int position;
        scanf("%d", &position);

        if (position < 1 || position > NUM_NUMBERS) {
            printf("Invalid position. Please try again.\n");
            continue;
        }

        guessedPositions[position - 1] = 1;

        printf("Guess even or odd (E/O): ");
        char guess;
        scanf(" %c", &guess);

        if ((guess == 'E' || guess == 'e') && numbers[position - 1] % 2 == 0) {
            score += 5;
            printf("Correct! You win 5 points.\n");
        } else if ((guess == 'O' || guess == 'o') && numbers[position - 1] % 2 != 0) {
            score += 5;
            printf("Correct! You win 5 points.\n");
        } else {
            printf("Incorrect. The number is %d, which is ", numbers[position - 1]);
            if (numbers[position - 1] % 2 == 0) {
                printf("even.\n");
            } else {
                printf("odd.\n");
            }
        }

        if (guessedPositions[0] && guessedPositions[1] && guessedPositions[2] &&
            guessedPositions[3] && guessedPositions[4]) {
            break;
        }
    }

    printf("Final score: %d\n", score);
}

int main(void) {
    playGame();
    return 0;
}

